#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Function to calculate GCD
int gcd(int a, int b) {
    if (b == 0)
        return a;
    return gcd(b, a % b);
}

// Function to calculate Frobenius number
int frobenius(int* arr, int n) {
    int g = arr[0];
    for (int i = 1; i < n; i++)
        g = gcd(g, arr[i]);
    return g;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int* arr = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++)
            scanf("%d", &arr[i]);
        int Q;
        scanf("%d", &Q);
        int a, b, c;
        scanf("%d %d %d", &a, &b, &c);
        int g = frobenius(arr, n);
        int max = -1;
        for (int i = 1; i <= Q; i++) {
            int Mi = (a * i + b) % c;
            if (Mi % g != 0 && Mi > max) {
                max = Mi;
            }
        }
        printf("%d\n", max);
        int A = 0, B = 0;
        for (int i = 1; i <= Q; i++) {
            int Mi = (a * i + b) % c;
            if (Mi % g != 0)
                A++;
            else
                B++;
        }
        printf("%d %d\n", A, B);
    }
    return 0;
}

